const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  LevelFormat, VerticalAlign, PageBreak, TabStopType, TabStopPosition
} = require('docx');
const fs = require('fs');

const ACCENT = "1F4E79";
const ACCENT2 = "2E75B6";
const LIGHT_BLUE = "D6E4F0";
const LIGHT_GRAY = "F2F2F2";
const MEDIUM_BLUE = "BDD7EE";
const WHITE = "FFFFFF";
const DARK = "1A1A1A";
const GREEN = "375623";
const GREEN_BG = "E2EFDA";
const ORANGE_BG = "FCE4D6";
const ORANGE = "843C0C";

function hd(text, level = HeadingLevel.HEADING_1) {
  const sizes = { [HeadingLevel.HEADING_1]: 32, [HeadingLevel.HEADING_2]: 26, [HeadingLevel.HEADING_3]: 22 };
  const colors = { [HeadingLevel.HEADING_1]: ACCENT, [HeadingLevel.HEADING_2]: ACCENT2, [HeadingLevel.HEADING_3]: ACCENT2 };
  return new Paragraph({
    spacing: { before: level === HeadingLevel.HEADING_1 ? 400 : 240, after: 120 },
    border: level === HeadingLevel.HEADING_1 ? {
      bottom: { style: BorderStyle.SINGLE, size: 4, color: ACCENT2, space: 4 }
    } : undefined,
    children: [new TextRun({ text, bold: true, size: sizes[level], color: colors[level], font: "Calibri" })]
  });
}

function para(text, opts = {}) {
  return new Paragraph({
    spacing: { before: opts.before || 80, after: opts.after || 80 },
    alignment: opts.align || AlignmentType.LEFT,
    children: [new TextRun({
      text, size: opts.size || 22, bold: opts.bold || false,
      color: opts.color || DARK, italic: opts.italic || false, font: "Calibri"
    })]
  });
}

function bullet(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    numbering: { reference: "bullets", level: 0 },
    children: [new TextRun({ text, size: 22, font: "Calibri", color: DARK })]
  });
}

function numbered(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    numbering: { reference: "numbers", level: 0 },
    children: [new TextRun({ text, size: 22, font: "Calibri", color: DARK })]
  });
}

function pageBreak() {
  return new Paragraph({ children: [new PageBreak()] });
}

function spacer() {
  return new Paragraph({ spacing: { before: 60, after: 60 }, children: [new TextRun("")] });
}

function borderRow(cells, widths, shading = null) {
  const border = { style: BorderStyle.SINGLE, size: 1, color: "C0C0C0" };
  const borders = { top: border, bottom: border, left: border, right: border };
  return new TableRow({
    children: cells.map((c, i) => new TableCell({
      borders,
      width: { size: widths[i], type: WidthType.DXA },
      shading: shading ? { fill: shading[i] || WHITE, type: ShadingType.CLEAR } : undefined,
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      verticalAlign: VerticalAlign.TOP,
      children: Array.isArray(c) ? c : [new Paragraph({
        spacing: { before: 40, after: 40 },
        children: [new TextRun({ text: c, size: 20, font: "Calibri", color: DARK })]
      })]
    }))
  });
}

function headerRow(cells, widths) {
  const border = { style: BorderStyle.SINGLE, size: 1, color: "AAAAAA" };
  const borders = { top: border, bottom: border, left: border, right: border };
  return new TableRow({
    tableHeader: true,
    children: cells.map((c, i) => new TableCell({
      borders,
      width: { size: widths[i], type: WidthType.DXA },
      shading: { fill: ACCENT, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: AlignmentType.CENTER,
        spacing: { before: 40, after: 40 },
        children: [new TextRun({ text: c, size: 21, bold: true, color: WHITE, font: "Calibri" })]
      })]
    }))
  });
}

function qaTable(qNum, qText, answer30, keywords, addIfAsked = null) {
  const border = { style: BorderStyle.SINGLE, size: 1, color: "BBBBBB" };
  const borders = { top: border, bottom: border, left: border, right: border };
  const rows = [];

  // Q row
  rows.push(new TableRow({
    children: [
      new TableCell({
        borders, width: { size: 900, type: WidthType.DXA },
        shading: { fill: ACCENT, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 120, right: 120 },
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [
          new TextRun({ text: `Q${qNum}`, size: 26, bold: true, color: WHITE, font: "Calibri" })
        ]})]
      }),
      new TableCell({
        borders, width: { size: 8460, type: WidthType.DXA },
        shading: { fill: LIGHT_BLUE, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 160, right: 120 },
        children: [new Paragraph({ children: [
          new TextRun({ text: qText, size: 23, bold: true, color: ACCENT, font: "Calibri" })
        ]})]
      })
    ]
  }));

  // Answer row
  rows.push(new TableRow({
    children: [
      new TableCell({
        borders, width: { size: 900, type: WidthType.DXA },
        shading: { fill: MEDIUM_BLUE, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 120, right: 120 },
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [
          new TextRun({ text: "30-sec", size: 18, bold: true, color: ACCENT, font: "Calibri" }),
        ]}), new Paragraph({ alignment: AlignmentType.CENTER, children: [
          new TextRun({ text: "Answer", size: 18, bold: true, color: ACCENT, font: "Calibri" }),
        ]})]
      }),
      new TableCell({
        borders, width: { size: 8460, type: WidthType.DXA },
        shading: { fill: WHITE, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 160, right: 120 },
        children: [new Paragraph({ children: [
          new TextRun({ text: answer30, size: 21, font: "Calibri", color: DARK })
        ]})]
      })
    ]
  }));

  // Keywords row
  rows.push(new TableRow({
    children: [
      new TableCell({
        borders, width: { size: 900, type: WidthType.DXA },
        shading: { fill: GREEN_BG, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 120, right: 120 },
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [
          new TextRun({ text: "Keywords", size: 17, bold: true, color: GREEN, font: "Calibri" })
        ]})]
      }),
      new TableCell({
        borders, width: { size: 8460, type: WidthType.DXA },
        shading: { fill: GREEN_BG, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 160, right: 120 },
        children: [new Paragraph({ children: [
          new TextRun({ text: keywords, size: 19, italic: true, color: GREEN, font: "Calibri" })
        ]})]
      })
    ]
  }));

  if (addIfAsked) {
    rows.push(new TableRow({
      children: [
        new TableCell({
          borders, width: { size: 900, type: WidthType.DXA },
          shading: { fill: ORANGE_BG, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          verticalAlign: VerticalAlign.CENTER,
          children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [
            new TextRun({ text: "Add-on", size: 17, bold: true, color: ORANGE, font: "Calibri" })
          ]})]
        }),
        new TableCell({
          borders, width: { size: 8460, type: WidthType.DXA },
          shading: { fill: ORANGE_BG, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 160, right: 120 },
          children: [new Paragraph({ children: [
            new TextRun({ text: addIfAsked, size: 19, italic: true, color: ORANGE, font: "Calibri" })
          ]})]
        })
      ]
    }));
  }

  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [900, 8460],
    rows,
    margins: { top: 0, bottom: 0, left: 0, right: 0 }
  });
}

// ===================== CONTENT =====================

const qaData = [
  // --- CATEGORY 1: OPENING ---
  {
    q: "Walk me through your background and why you're the right fit for this PLM SME role.",
    a: "Good morning. I'm Joonha Lee — 20-plus years in electronics, communications, and defense systems, with 15 years focused on naval ship and submarine programs. I've translated customer requirements into specs, interface documents, test plans, and delivery schedules, and I've closed FAT, SAT, and field issues with evidence every time. That's exactly the discipline this role needs: structured requirements, controlled change, and evidence-based customer communication. I'm ready to apply that directly to Korean shipyards through AVEVA PLM.",
    kw: "Naval systems, 20+ years, requirements, FAT/SAT, evidence-based, customer-facing",
    add: "If asked to elaborate: 'I can immediately contribute to PoC structuring, workshop facilitation, requirements definition, and customer issue closure while building deeper AVEVA product knowledge in parallel.'"
  },
  {
    q: "How do you understand this role — what does a PLM SME at AVEVA Marine actually do?",
    a: "This isn't a standard software support job. A PLM SME at AVEVA Marine MCoE bridges Korean shipyard operations and AVEVA's global product teams. Concretely: I collect and structure shipyard PLM requirements, translate them into product-ready specifications for Product Portfolio and Development, validate new features from the customer's perspective before release, lead technical workshops and PoC demonstrations, and own issue resolution end-to-end. It's a principal-level bridge role — field expertise on one side, product roadmap on the other.",
    kw: "Bridge role, MCoE, requirements → product requirements → validation → issue closure",
    add: "Describe the full chain: customer requirement → structured product requirement → feature validation → customer adoption → issue closure."
  },
  {
    q: "Why AVEVA, and why the Busan Marine Center of Excellence specifically?",
    a: "From naval and defense projects, I know first-hand that poor engineering data management directly causes schedule overruns and rework. AVEVA is the company solving exactly that problem at scale for shipbuilding. The Busan MCoE is where AVEVA interfaces closest with Korean big-three shipyards — HD HHI, Samsung Heavy, and Hanwha Ocean. I want to be where the real shipbuilding challenges are being solved, not at headquarters. AVEVA is also pushing AI-integrated, data-centric PLM — what they're calling ALM — and I want to be part of that transformation.",
    kw: "Busan MCoE, Korean big-three, data-centric PLM / ALM, shipbuilding transformation",
    add: "Mention AVEVA Day Korea 2025 and the Unified Engineering / ALM vision if relevant."
  },
  {
    q: "Your AVEVA PLM product experience is limited. How will you contribute at Principal level from day one?",
    a: "That's fair, and I won't overstate it. But here's the key point: PLM exists to solve problems I've already lived — configuration control, change impact, document traceability, approval workflows, and customer escalations in high-complexity engineering programs. In submarine and destroyer programs, when data wasn't controlled, ships were delayed. I structured the requirements, the test evidence, and the closure reports. The product label changes; the engineering discipline doesn't. I'll close the AVEVA product gap fast, while contributing to requirement structuring and issue management from day one.",
    kw: "Acknowledge gap honestly, field relevance, rapid ramp-up, immediate contribution areas",
    add: "'My 30-day plan: intensive product learning + map my defense/naval experience to AVEVA PLM workflows + join one active customer issue.'"
  },

  // --- CATEGORY 2: ARCHITECTURE ---
  {
    q: "How would you design the next-generation PLM architecture for a large Korean shipyard?",
    a: "I'd build it in phases — not a big-bang replacement. AVEVA becomes the engineering and lifecycle backbone: 3D models, EBOM, documents, configuration, approval workflows, and change control all live there. Legacy systems stay connected through a controlled middleware layer using stable APIs and adapters. Data structured by project, vessel, discipline, zone, block, and work package — so large multi-project shipyards can manage scale. Key principle: standardize future programs around AVEVA, coexist safely with legacy, migrate valuable historical data in controlled waves.",
    kw: "Phased architecture, AVEVA backbone, middleware, legacy coexistence, data segmentation",
    add: "Add data governance layers: active working data vs approved baseline vs archived history — each with different access, performance, and retention rules."
  },
  {
    q: "How do you design for performance and scalability with thousands of concurrent users and massive hull/outfitting models?",
    a: "Performance must be designed at architecture level — server tuning alone won't cut it. I'd segment models by vessel, discipline, zone, block, system, and work package so users load only what's relevant to them. I'd separate active working data, approved baseline, and historical data — daily work stays fast. Technically: indexing, caching, load-balanced application servers, storage tiering, clear check-in/check-out rules, and event-driven integration. I'd monitor real user KPIs — model load time, search response, save time, workflow approval — not just server uptime.",
    kw: "Model segmentation, data tiering, load balancing, caching, user KPI monitoring",
  },
  {
    q: "How would you structure the integration layer so legacy systems can be retired or replaced later without rebuilding everything?",
    a: "Never point-to-point. I'd design a decoupled middleware layer where AVEVA communicates with stable business interfaces — equipment data, BOM, documents, material status, production status, change notices — not directly with individual legacy tools. Each legacy system gets its own adapter; the canonical data model and mapping rules stay constant. When ERP is upgraded or a legacy CAD tool is retired, only its adapter changes. The PLM architecture stays stable. That's the difference between a maintainable integration and a spaghetti nightmare.",
    kw: "Decoupled middleware, adapter pattern, canonical data model, stable business interface",
  },
  {
    q: "How do you define clear functional boundaries between AVEVA PLM, ERP, and MES?",
    a: "I use system-of-record ownership as the guiding principle. AVEVA PLM owns everything about what should be built: 3D model structure, EBOM, equipment tags, design documents, revisions, design maturity, and engineering change control. ERP owns what is bought and costed: purchasing, supplier data, inventory, commercial BOM, financial execution. MES owns what is actually built and installed: work orders, shop-floor progress, inspection results, as-built status. Clear ownership prevents data duplication, conflicting records, and integration confusion — the three things that kill large shipbuilding PLM programs.",
    kw: "PLM = what to build | ERP = cost/procurement | MES = execution/as-built",
  },
  {
    q: "How do you govern PLM-ERP-MES integration so it remains maintainable through product upgrades?",
    a: "I treat integration as a long-term product in its own right, not a one-time customization. That means stable APIs or message queues — not direct DB links — and a canonical data model for key business objects: EBOM, material requests, change notices, work packages, production status. Every interface has an owner, version, mapping rule, error-handling procedure, and test case set. Before any PLM, ERP, or MES upgrade, I run regression tests in staging using representative scenarios — engineering release, BOM transfer, change impact, production feedback — before touching production.",
    kw: "Interface governance, versioning, data contracts, regression testing, staging environment",
  },

  // --- CATEGORY 3: REQUIREMENTS ---
  {
    q: "A shipyard asks vaguely: 'We need better late owner variation management.' How do you convert that into actionable product requirements?",
    a: "I don't jump to solutions. First I run structured workshops with design, planning, production, procurement, quality, and PM teams to understand the real problem — who raises the variation, at what project stage, which 3D objects, drawings, BOM items, and work packages are affected, who approves it, where the delays actually happen. Then I classify requirements into workflow, data objects, approval authority, revision control, traceability, and cost/schedule/material impact. Real cases become user stories with acceptance criteria — ready for Product Portfolio and R&D to act on.",
    kw: "Workshop-first, structured decomposition, user stories, acceptance criteria, product-ready requirements",
    add: "When stakeholder priorities conflict, resolve by business impact — customer schedule risk > internal convenience."
  },
  {
    q: "How do you make requirements testable so R&D and QA can work from them?",
    a: "Scenario-based and measurable — not 'the system shall support changes.' Real example: if an owner requests an equipment change after design approval, the system must create a formal variation request, link it to affected 3D objects, drawings, BOM items, purchase orders, and work packages, route it to the correct approvers, maintain revision history with status, owner, date, and reason, block inconsistent release, and generate a cost/material/schedule impact summary. That's a test case, not a requirement description. I agree pass/fail criteria with the shipyard, QA, and R&D before development starts.",
    kw: "Scenario-based criteria, measurable, link-to-artifact traceability, pass/fail agreement",
  },
  {
    q: "How do you handle conflicting requirements from multiple stakeholder groups — design, production, procurement, and project management?",
    a: "Conflict is normal in complex programs — I don't try to eliminate it, I manage it transparently. I document all requirements with their source and business justification, then prioritize by impact on ship delivery schedule, production cost, or customer satisfaction. When groups conflict, I bring them together with data — 'If we implement this change workflow without production input, what's the rework risk?' Decisions get documented with owner and rationale. My role is to make the tradeoff visible and structured, not to pick winners politically.",
    kw: "Structured prioritization, impact-based trade-off, documented decisions, transparent process",
  },

  // --- CATEGORY 4: PoC & WORKSHOP ---
  {
    q: "A skeptical customer gives you four weeks and limited anonymized data for a PoC. How do you scope it?",
    a: "Four weeks means tight scope — I'm not proving the full PLM vision. I identify the customer's top two or three pain points — change control, model-to-document traceability, BOM impact, approval workflow — and build scenarios around those. Before day one, I agree success criteria with the customer in writing. I check whether the anonymized data includes tags, revisions, relationships, and sample change cases. If it doesn't, I use realistic synthetic data and say so transparently. The PoC proves specific value — not everything, but the right things.",
    kw: "Tight scoping, success criteria upfront, top pain points, synthetic data transparency",
    add: "FOCUSED → MEASURABLE → ACHIEVABLE → TRANSPARENT: four words that make the difference between a PoC that converts and one that leaves the customer unconvinced."
  },
  {
    q: "How do you configure and present a PoC so the customer sees business value, not just product features?",
    a: "I build a business storyline — not a feature list. I set up a small AVEVA environment with realistic project structure, user roles, document types, equipment tags, BOM items, change workflow, and dashboards. The demo follows an end-to-end scenario: an owner requests a late design change — we register it, link affected model objects, drawings, BOM items, and approvals, and show the impact summary. The customer sees traceability, eliminated manual checking, faster impact analysis, and decision visibility — outcomes they care about. I show limitations transparently too; that builds trust.",
    kw: "Business storyline, end-to-end scenario, traceability, impact visibility, transparent limitations",
  },
  {
    q: "How do you prepare and run a technical workshop that drives customer adoption, not just product awareness?",
    a: "A workshop is a customer problem-solving session — not a product demo with Q&A at the end. Before I go in, I confirm participant roles, pain points, target workflows, and expected outcomes. Structure: customer problem → relevant AVEVA workflow → live demo → data considerations → limitations → Q&A → clear action items with owners and dates. During Q&A I classify questions — function, process, customization, product enhancement — so nothing falls through the cracks. The post-workshop minutes are as important as the session itself.",
    kw: "Problem-solving session, pre-confirmed outcomes, Q&A classification, action items with owners",
  },
  {
    q: "How do you structure a technical proposal so it wins customer trust, not just technical approval?",
    a: "Start with the customer's problem and its business impact — not a feature list. Then: target process, proposed AVEVA solution scope, system architecture, data flow, required configuration, customization, and integration, implementation phases, assumptions, risks, test criteria, and expected customer value. The section most proposals skip: customer-side prerequisites — data quality, decision ownership, process standardization readiness. That transparency is what separates a proposal customers trust from one they sign and then blame you for later.",
    kw: "Problem-impact-solution-architecture-risk-validation-value, customer prerequisites",
  },

  // --- CATEGORY 5: TECHNICAL SUPPORT ---
  {
    q: "A defect occurs only in the customer environment — intermittently and only under load. How do you investigate?",
    a: "I don't assume it's a product bug first. I treat it as an environment-specific investigation. I collect precise evidence: affected user, project, model scope, operation steps, time, error message, logs, system load, database state, integration activity, and recent configuration changes. I look for patterns — specific project, discipline, user role, dataset size, workflow status, network condition, or concurrent user load. Then I isolate variables: smaller vs full dataset, single vs multiple users, integration on vs off, standard vs customer-specific configuration. That separates data, config, infrastructure, integration, and product behavior.",
    kw: "Evidence collection, pattern identification, variable isolation, systematic environment comparison",
  },
  {
    q: "A critical defect is blocking a ship delivery milestone. R&D needs more time. The customer's management is calling daily. How do you communicate?",
    a: "I set a communication rhythm — transparent, frequent, no overpromising. First update: 'This is blocking a critical milestone. We're treating it as a P1 escalation.' Then I become the single point of contact and set a fixed daily update time. Each update: current status, what was tested, what was ruled out, what R&D is analyzing, next action, owner, and next checkpoint. I never say 'fixed soon' without evidence. If there's a safe workaround or rollback procedure, I present it with explicit risks and limitations. I separate facts from assumptions every time.",
    kw: "Transparent rhythm, no overpromising, single point of contact, fact vs assumption separation",
  },
  {
    q: "How do you validate new PLM features before release from a real shipbuilding customer perspective?",
    a: "I test against real shipbuilding workflows — not basic feature operation checks. I review release notes, identify affected workflows, and design scenarios: design change, BOM and equipment configuration, document approval, access control, large data handling, and integration behavior. Results include evidence, reproduction conditions, severity, customer impact, suggested improvements, and workshop talking points. My standard is FAT/SAT level: every test leaves a traceable record. If I can't sign off on it like a field acceptance test, it's not ready for the customer.",
    kw: "Shipbuilding workflow scenarios, FAT/SAT discipline, traceable test records, customer impact assessment",
  },
  {
    q: "How do you approach customization and integration requests without creating long-term maintenance problems?",
    a: "I check standard functionality first — always. If customization or integration is genuinely needed, I define scope, interface specification, data ownership, test criteria, performance risk, upgrade impact, and rollback plan before a single line of code is written. Uncontrolled customization looks like a solution today and becomes a blocker at the next AVEVA upgrade. A Principal Engineer's job is to manage that boundary — deliver what the customer needs without accumulating architecture debt. Sometimes the right answer is 'we can configure this, and here's why that's actually better for you.'",
    kw: "Standard-first, scope definition, upgrade impact assessment, architecture discipline",
  },

  // --- CATEGORY 6: AVEVA PRODUCT KNOWLEDGE ---
  {
    q: "What do you know about AVEVA's Marine PLM solution stack, and where do you see it heading?",
    a: "AVEVA Marine PLM centers on AVEVA NET for information management and lifecycle control, AVEVA Marine — Hull and Outfitting — for 3D design, AVEVA E3D Design for the next-generation platform, and AVEVA MARS for material control, production planning, and project logistics. The direction I see from AVEVA Day Korea 2025 is clear: AI-integrated, data-centric PLM — what AVEVA is calling ALM, Asset Lifecycle Management — bridging ship engineering, manufacturing, and operations in a unified platform. Korean shipyards are exactly the right proving ground for that vision.",
    kw: "AVEVA NET, Hull & Outfitting, E3D Design, MARS, ALM, AI-integrated data-centric PLM",
    add: "If asked about gaps: 'I'll close my hands-on product knowledge gap in the first 30 days through intensive self-study, AVEVA documentation, and working alongside the MCoE team.'"
  },
  {
    q: "AVEVA talks about 'Unified Engineering' and 'ALM' — what's your understanding and how does it relate to Korean shipyards?",
    a: "AVEVA Unified Engineering is the vision of connecting ship design, production, and operations data in a single coherent platform — eliminating the silos between CAD tools, PLM systems, production planning, and operational data. ALM, Asset Lifecycle Management, extends PLM beyond construction into ship operations and maintenance. For Korean shipyards, this is directly relevant: HD HHI, Samsung Heavy, and Hanwha Ocean are all competing on delivery speed and quality for LNG carriers, warships, and green-fuel vessels. A shipyard with unified engineering data has a real competitive advantage.",
    kw: "Unified Engineering, ALM, silos elimination, Korean big-three, competitive advantage",
  },

  // --- CATEGORY 7: LEADERSHIP & MENTORING ---
  {
    q: "Describe your leadership and mentoring approach as a Principal Engineer.",
    a: "I lead through structure and example — I give people repeatable ways to do quality work, not just advice in the moment. For customer issues, I teach engineers to build a proper technical package first: business background, impact, reproduction conditions, related feature, escalation point. For workshops and PoC, I use checklists and sample deliverables so the whole team produces consistent output. Before customer meetings, I rehearse with junior engineers — likely questions, technical boundaries, escalation paths. Good mentoring means the person can handle it without me next time.",
    kw: "Structure over advice, templates, checklists, pre-meeting rehearsal, independence goal",
  },
  {
    q: "How do you motivate and align a team of highly skilled technical consultants with different priorities?",
    a: "I align through clarity — clear problem definition, clear ownership, and clear success criteria. With skilled professionals, the fastest way to lose alignment is ambiguity: 'handle this customer' versus 'close this specific defect by confirming reproduction, isolating to these variables, and documenting the workaround by Friday.' I also create space for technical disagreement early — I'd rather hear a dissenting view in the team meeting than find out the customer was told conflicting things. Shared structure enables autonomy; vague instructions create politics.",
    kw: "Clarity over motivation speeches, specific ownership, early disagreement space, shared structure",
  },
  {
    q: "How do you handle multiple competing commitments — customer escalations, PoC preparation, feature validation, and internal reporting all at once?",
    a: "When pressure peaks, I get more granular, not more vague. I prioritize by customer impact, deadline, severity, and decision urgency. Urgent escalations get immediate triage — I don't let them age. Longer-term work gets broken into small visible deliverables: an issue summary, a customer update, a test evidence file, a section of a proposal. I work in blocks — each one produces something the team or customer can see. My productivity measure isn't hours worked; it's how many customer issues actually moved forward today.",
    kw: "Granular prioritization, triage, small visible deliverables, output-driven discipline",
  },

  // --- CATEGORY 8: PERSONAL STRENGTHS ---
  {
    q: "What's your strongest professional strength, and how does it apply here?",
    a: "Closure discipline. When I take an issue, I define from the start: who owns it, what evidence is required, what condition constitutes closure. I don't consider a customer issue closed until it's reproduced or confirmed, analyzed, corrected, validated with evidence, communicated to the customer, and documented. In naval programs, a 'verbally resolved' issue that comes back at FAT or sea trials costs everyone significantly more. That same discipline directly applies to AVEVA customer issue management, feature validation, and PoC execution.",
    kw: "Closure discipline, evidence-based, definition of done, naval program discipline applied to PLM",
  },
  {
    q: "You have experience with EPLAN. How is that relevant to AVEVA PLM?",
    a: "I won't overclaim EPLAN as equivalent to AVEVA PLM product experience — they're different tools. But the reason I engaged with EPLAN was to solve a standardization problem: electrical component data, wiring information, and documents weren't consistent across projects, which caused rework and change control failures. That experience showed me directly why engineering data standardization, document consistency, and change traceability matter. AVEVA PLM solves those same problems at ship-program scale. The mindset carries over fully; the product knowledge I'll build.",
    kw: "Don't overclaim, data standardization mindset, change control relevance, product knowledge gap acknowledged",
  },
  {
    q: "Are you willing and able to travel internationally? How do you handle working across time zones with global R&D teams?",
    a: "Absolutely — and I've done it. In defense programs, coordinating with international suppliers, classification societies, and customer representatives across time zones was routine. My approach is asynchronous-first: I document thoroughly so nothing waits on a meeting, I prepare concise written briefings before calls so the sync time is used for decisions, not background, and I follow up with clear written action items. Willingness to travel also means I can represent Korean customer interests directly at AVEVA's global development and product teams — which is genuinely valuable in this role.",
    kw: "International readiness, asynchronous-first, documented briefings, global team collaboration",
  },

  // --- CATEGORY 9: SITUATIONAL / BEHAVIORAL ---
  {
    q: "Tell me about a time you had to solve a critical technical problem with incomplete information and time pressure.",
    a: "In a submarine communication system acceptance test, a critical failure occurred with delivery in 48 hours. I didn't have full diagnostic data — the customer environment was partially restricted. I built a hypothesis matrix: component failure, interface mismatch, configuration drift, environmental factor. I started with the fastest-to-test variables first, used substitution, and isolated the failure to a firmware-level timing conflict with a specific hardware revision. We had a workaround tested and documented within 36 hours. The lesson: even with incomplete data, structured hypothesis testing beats random trial-and-error every time.",
    kw: "Hypothesis matrix, structured isolation, workaround documentation, 48-hour delivery pressure",
  },
  {
    q: "Describe a time you had to push back on a customer request to protect project or system integrity.",
    a: "In a naval project, a customer requested an undocumented hardware modification post-SAT to improve a specific operational metric. The change would have invalidated our configuration baseline and required re-certification. I acknowledged the merit of the request clearly, then explained the risks: scope creep, re-test requirements, certification impact, and schedule cost. I proposed a formal change request process with proper evaluation — and the customer agreed. My approach: never 'no' without a structured alternative. Protecting integrity and maintaining customer trust aren't opposites if you handle it professionally.",
    kw: "Push back with respect, structured alternative, change request process, integrity vs trust balance",
  },
  {
    q: "Have you ever had to deliver bad news to a customer executive? How did you handle it?",
