const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  AlignmentType, HeadingLevel, BorderStyle, WidthType, ShadingType,
  LevelFormat, VerticalAlign, PageBreak
} = require('docx');
const fs = require('fs');

const ACCENT = "1F4E79";
const ACCENT2 = "2E75B6";
const LIGHT_BLUE = "D6E4F0";
const MEDIUM_BLUE = "BDD7EE";
const WHITE = "FFFFFF";
const DARK = "1A1A1A";
const GREEN = "375623";
const GREEN_BG = "E2EFDA";
const ORANGE_BG = "FCE4D6";
const ORANGE = "843C0C";

function hd(text, level = HeadingLevel.HEADING_1) {
  const sizes = { [HeadingLevel.HEADING_1]: 32, [HeadingLevel.HEADING_2]: 26, [HeadingLevel.HEADING_3]: 22 };
  const colors = { [HeadingLevel.HEADING_1]: ACCENT, [HeadingLevel.HEADING_2]: ACCENT2, [HeadingLevel.HEADING_3]: ACCENT2 };
  return new Paragraph({
    spacing: { before: level === HeadingLevel.HEADING_1 ? 400 : 240, after: 120 },
    border: level === HeadingLevel.HEADING_1 ? {
      bottom: { style: BorderStyle.SINGLE, size: 4, color: ACCENT2, space: 4 }
    } : undefined,
    children: [new TextRun({ text, bold: true, size: sizes[level], color: colors[level], font: "Malgun Gothic" })]
  });
}

function para(text, opts = {}) {
  return new Paragraph({
    spacing: { before: opts.before || 80, after: opts.after || 80 },
    alignment: opts.align || AlignmentType.LEFT,
    children: [new TextRun({
      text, size: opts.size || 22, bold: opts.bold || false,
      color: opts.color || DARK, italic: opts.italic || false, font: "Malgun Gothic"
    })]
  });
}

function bullet(text) {
  return new Paragraph({
    spacing: { before: 60, after: 60 },
    numbering: { reference: "bullets", level: 0 },
    children: [new TextRun({ text, size: 22, font: "Malgun Gothic", color: DARK })]
  });
}

function pageBreak() {
  return new Paragraph({ children: [new PageBreak()] });
}
function spacer() {
  return new Paragraph({ spacing: { before: 60, after: 60 }, children: [new TextRun("")] });
}

function headerRow(cells, widths) {
  const border = { style: BorderStyle.SINGLE, size: 1, color: "AAAAAA" };
  const borders = { top: border, bottom: border, left: border, right: border };
  return new TableRow({
    tableHeader: true,
    children: cells.map((c, i) => new TableCell({
      borders,
      width: { size: widths[i], type: WidthType.DXA },
      shading: { fill: ACCENT, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      verticalAlign: VerticalAlign.CENTER,
      children: [new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: c, size: 21, bold: true, color: WHITE, font: "Malgun Gothic" })]
      })]
    }))
  });
}

function borderRow(cells, widths, shading = null) {
  const border = { style: BorderStyle.SINGLE, size: 1, color: "C0C0C0" };
  const borders = { top: border, bottom: border, left: border, right: border };
  return new TableRow({
    children: cells.map((c, i) => new TableCell({
      borders,
      width: { size: widths[i], type: WidthType.DXA },
      shading: shading ? { fill: shading[i] || WHITE, type: ShadingType.CLEAR } : undefined,
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      verticalAlign: VerticalAlign.TOP,
      children: Array.isArray(c) ? c : [new Paragraph({
        spacing: { before: 40, after: 40 },
        children: [new TextRun({ text: c, size: 20, font: "Malgun Gothic", color: DARK })]
      })]
    }))
  });
}

function qaTable(qNum, qText, answer30, keywords, addIfAsked = null) {
  const border = { style: BorderStyle.SINGLE, size: 1, color: "BBBBBB" };
  const borders = { top: border, bottom: border, left: border, right: border };
  const rows = [];

  rows.push(new TableRow({
    children: [
      new TableCell({
        borders, width: { size: 900, type: WidthType.DXA },
        shading: { fill: ACCENT, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 120, right: 120 },
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [
          new TextRun({ text: `Q${qNum}`, size: 26, bold: true, color: WHITE, font: "Malgun Gothic" })
        ]})]
      }),
      new TableCell({
        borders, width: { size: 8460, type: WidthType.DXA },
        shading: { fill: LIGHT_BLUE, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 160, right: 120 },
        children: [new Paragraph({ children: [
          new TextRun({ text: qText, size: 23, bold: true, color: ACCENT, font: "Malgun Gothic" })
        ]})]
      })
    ]
  }));

  rows.push(new TableRow({
    children: [
      new TableCell({
        borders, width: { size: 900, type: WidthType.DXA },
        shading: { fill: MEDIUM_BLUE, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 120, right: 120 },
        verticalAlign: VerticalAlign.CENTER,
        children: [
          new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "30초", size: 18, bold: true, color: ACCENT, font: "Malgun Gothic" })]}),
          new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: "답변", size: 18, bold: true, color: ACCENT, font: "Malgun Gothic" })]})
        ]
      }),
      new TableCell({
        borders, width: { size: 8460, type: WidthType.DXA },
        shading: { fill: WHITE, type: ShadingType.CLEAR },
        margins: { top: 100, bottom: 100, left: 160, right: 120 },
        children: [new Paragraph({ children: [
          new TextRun({ text: answer30, size: 21, font: "Malgun Gothic", color: DARK })
        ]})]
      })
    ]
  }));

  rows.push(new TableRow({
    children: [
      new TableCell({
        borders, width: { size: 900, type: WidthType.DXA },
        shading: { fill: GREEN_BG, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 120, right: 120 },
        verticalAlign: VerticalAlign.CENTER,
        children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [
          new TextRun({ text: "키워드", size: 17, bold: true, color: GREEN, font: "Malgun Gothic" })
        ]})]
      }),
      new TableCell({
        borders, width: { size: 8460, type: WidthType.DXA },
        shading: { fill: GREEN_BG, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 160, right: 120 },
        children: [new Paragraph({ children: [
          new TextRun({ text: keywords, size: 19, italic: true, color: GREEN, font: "Malgun Gothic" })
        ]})]
      })
    ]
  }));

  if (addIfAsked) {
    rows.push(new TableRow({
      children: [
        new TableCell({
          borders, width: { size: 900, type: WidthType.DXA },
          shading: { fill: ORANGE_BG, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          verticalAlign: VerticalAlign.CENTER,
          children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [
            new TextRun({ text: "추가답변", size: 17, bold: true, color: ORANGE, font: "Malgun Gothic" })
          ]})]
        }),
        new TableCell({
          borders, width: { size: 8460, type: WidthType.DXA },
          shading: { fill: ORANGE_BG, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 160, right: 120 },
          children: [new Paragraph({ children: [
            new TextRun({ text: addIfAsked, size: 19, italic: true, color: ORANGE, font: "Malgun Gothic" })
          ]})]
        })
      ]
    }));
  }

  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [900, 8460],
    rows
  });
}

// ===================== KOREAN CONTENT =====================

const qaData = [
  // A: 오프닝 & 지원동기
  {
    q: "자기소개와 이 직무에 지원하게 된 배경을 말씀해 주십시오.",
    a: "안녕하십니까, 이준하입니다. 전자·통신·방산 시스템 분야에서 20년 이상, 그 중 15년을 해군 함정과 잠수함 통신체계 프로젝트에 집중했습니다. 고객 요구사항을 사양서, 인터페이스 문서, 시험 기준, 납품 일정으로 구체화하고 FAT·SAT·현장 이슈를 근거 기반으로 끝까지 닫아온 경험이 있습니다. 이 PLM SME 직무에서도 같은 방식으로 한국 조선소 요구사항을 AVEVA 제품 개발에 연결하고, PoC·워크숍·이슈 클로징을 주도하겠습니다.",
    kw: "해군 시스템, 20년+, 요구사항, FAT/SAT, 근거 기반, 고객 대응",
    add: "'즉시 기여 가능 영역: 요구사항 구조화, PoC 기획, 워크숍 진행, 이슈 클로징' — 제품 지식 심화와 병행하겠습니다."
  },
  {
